                                    <button 
                                        onClick={() => setPriority('LOW')} 
                                        className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'LOW' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}
                                    >
                                        {t('prio_low')}
                                    </button>
                                    <button 
                                        onClick={() => setPriority('NORMAL')} 
