const LogisticsTab: React.FC<LogisticsTabProps> = ({ tasks, onToggleTask, onSetInProgress, onDeleteTask, hasPermission, logisticsOperations }) => {
    const { t, language } = useLanguage();

    // Logic to categorize tasks
    const { inboundTasks, outboundTasks, internalTasks } = useMemo(() => {
        const logTasks = tasks.filter(t => t.type === 'logistics' && !t.isDone);

        // Define keywords for classification (should match DB values or be configurable)
        // Using standard naming conventions often used in Logistics
        const inboundKeywords = ['VYKLÁDKA', 'UNLOADING', 'ZASKLADNENIE', 'PUT-AWAY', 'PRÍJEM', 'INBOUND'];
        const outboundKeywords = ['NAKLÁDKA', 'LOADING', 'EXPEDÍCIA', 'OUTBOUND', 'VÝDAJ'];

        const inbound: Task[] = [];
        const outbound: Task[] = [];
        const internal: Task[] = [];

        logTasks.forEach(task => {
            const op = task.workplace?.toUpperCase() || '';
            if (inboundKeywords.some(k => op.includes(k))) {
                inbound.push(task);
            } else if (outboundKeywords.some(k => op.includes(k))) {
                outbound.push(task);
            } else {
                internal.push(task);
            }
        });

        // Sort by priority and creation time
        const sorter = (a: Task, b: Task) => {
            if (a.priority === 'URGENT' && b.priority !== 'URGENT') return -1;
            if (a.priority !== 'URGENT' && b.priority === 'URGENT') return 1;
            return (a.createdAt || 0) - (b.createdAt || 0);
        };

        return {
            inboundTasks: inbound.sort(sorter),
            outboundTasks: outbound.sort(sorter),
            internalTasks: internal.sort(sorter)
        };
    }, [tasks]);

    const formatTimeElapsed = (timestamp: number) => {
        const diff = Date.now() - timestamp;
        const minutes = Math.floor(diff / 60000);
        const hours = Math.floor(minutes / 60);

        if (hours > 0) return `${hours}h ${minutes % 60}m`;
        return `${minutes} min`;
    };

    const renderCard = (task: Task) => {
        const isUrgent = task.priority === 'URGENT';
        const isResolving = task.isInProgress;

        return (
            <div key={task.id} className={`relative bg-gray-800 rounded-xl p-4 shadow-lg border-l-4 mb-4 transition-all hover:translate-y-[-2px] ${isUrgent ? 'border-red-500' : isResolving ? 'border-yellow-400' : 'border-gray-600'}`}>
                {/* Header: Ref & Time */}
                <div className="flex justify-between items-start mb-2">
                    <h3 className="text-2xl font-black text-white tracking-wider font-mono">{task.partNumber}</h3>
                    <div className="flex flex-col items-end">
                         <span className="text-xs text-gray-400 font-mono">
                            {new Date(task.createdAt || 0).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                         </span>
                         <span className={`text-sm font-bold ${isUrgent ? 'text-red-400 animate-pulse' : 'text-gray-500'}`}>
                            ⏱ {formatTimeElapsed(task.createdAt || 0)}
                         </span>
                    </div>
                </div>

                {/* Operation & Qty */}
                <div className="flex justify-between items-center mb-4">
                    <span className="bg-gray-700 px-2 py-1 rounded text-sm font-bold text-sky-300 uppercase">
                        {task.workplace}
                    </span>
                    <span className="text-xl font-bold text-white">
                        {task.quantity} <span className="text-sm font-normal text-gray-400">{task.quantityUnit || 'pal'}</span>
                    </span>
                </div>

                {/* Status Bar */}
                {isResolving && (
                    <div className="mb-3 bg-yellow-900/30 border border-yellow-600/50 rounded px-2 py-1 text-center">
                        <span className="text-yellow-400 text-xs font-bold uppercase animate-pulse">
                            {t('status_resolving')} {task.inProgressBy}
                        </span>
                    </div>
                )}

                {/* Actions */}
                <div className="flex gap-2 border-t border-gray-700 pt-3">
                     {/* Resolve / Start */}
                     {hasPermission('perm_btn_resolve') && (
                        <button 
                            onClick={() => onSetInProgress(task.id)}
                            className={`flex-1 py-2 rounded-lg flex items-center justify-center transition-colors ${isResolving ? 'bg-yellow-600 hover:bg-yellow-500 text-white' : 'bg-gray-700 hover:bg-gray-600 text-gray-300'}`}
                        >
                            {isResolving ? <PauseIcon className="w-6 h-6"/> : <PlayIcon className="w-6 h-6"/>}
                        </button>
                     )}

                     {/* Finish */}
                     {hasPermission('perm_btn_finish') && (
                        <button 
                            onClick={() => onToggleTask(task.id)}
                            className="flex-1 py-2 bg-green-700 hover:bg-green-600 text-white rounded-lg flex items-center justify-center transition-colors"
                        >
                            <CheckIcon className="w-6 h-6"/>
                        </button>
                     )}

                     {/* Delete */}
                     {hasPermission('perm_btn_delete') && (
                        <button 
                            onClick={() => { if(window.confirm(t('miss_delete_confirm'))) onDeleteTask(task.id) }}
                            className="w-10 py-2 bg-red-900/50 hover:bg-red-800 text-red-400 rounded-lg flex items-center justify-center transition-colors border border-red-900"
                        >
                            <TrashIcon className="w-5 h-5"/>
                        </button>
                     )}
                </div>
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col md:flex-row gap-4 pb-20 animate-fade-in">
            {/* INBOUND COLUMN */}
            <div className="flex-1 bg-gray-900/50 rounded-xl border border-gray-700 flex flex-col overflow-hidden">
                <div className="p-4 bg-gray-800 border-b border-gray-700 flex justify-between items-center sticky top-0 z-10 shadow-md">
                    <div className="flex items-center gap-2">
                        <div className="bg-sky-900/50 p-2 rounded-lg">
                             <ArrowDownIcon className="w-6 h-6 text-sky-400" />
                        </div>
                        <h2 className="text-xl font-black text-white uppercase tracking-wider">{t('log_inbound')}</h2>
                    </div>
                    <span className="bg-sky-600 text-white text-xs font-bold px-2 py-1 rounded-full">{inboundTasks.length}</span>
                </div>
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-gradient-to-b from-gray-900 to-gray-800">
                    {inboundTasks.length === 0 ? (
                        <div className="h-40 flex flex-col items-center justify-center text-gray-600">
                            <TruckIcon className="w-12 h-12 mb-2 opacity-20"/>
                            <p className="text-sm italic">{t('no_data')}</p>
                        </div>
                    ) : (
                        inboundTasks.map(renderCard)
                    )}
                </div>
            </div>

            {/* OUTBOUND COLUMN */}
            <div className="flex-1 bg-gray-900/50 rounded-xl border border-gray-700 flex flex-col overflow-hidden">
                <div className="p-4 bg-gray-800 border-b border-gray-700 flex justify-between items-center sticky top-0 z-10 shadow-md">
                    <div className="flex items-center gap-2">
                         <div className="bg-orange-900/50 p-2 rounded-lg">
                             <ArrowUpIcon className="w-6 h-6 text-orange-400" />
                        </div>
                        <h2 className="text-xl font-black text-white uppercase tracking-wider">{t('log_outbound')}</h2>
                    </div>
                    <span className="bg-orange-600 text-white text-xs font-bold px-2 py-1 rounded-full">{outboundTasks.length}</span>
                </div>
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-gradient-to-b from-gray-900 to-gray-800">
                    {outboundTasks.length === 0 ? (
                         <div className="h-40 flex flex-col items-center justify-center text-gray-600">
                            <TruckIcon className="w-12 h-12 mb-2 opacity-20"/>
                            <p className="text-sm italic">{t('no_data')}</p>
                        </div>
                    ) : (
                        outboundTasks.map(renderCard)
                    )}
                </div>
            </div>

            {/* INTERNAL COLUMN (Optional, collapsed on mobile maybe?) */}
            {internalTasks.length > 0 && (
                <div className="flex-1 md:max-w-xs bg-gray-900/50 rounded-xl border border-gray-700 flex flex-col overflow-hidden opacity-80">
                    <div className="p-4 bg-gray-800 border-b border-gray-700 flex justify-between items-center sticky top-0 z-10">
                        <h2 className="text-lg font-bold text-gray-400 uppercase tracking-wider">{t('log_internal')}</h2>
                        <span className="bg-gray-600 text-white text-xs font-bold px-2 py-1 rounded-full">{internalTasks.length}</span>
                    </div>
                    <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                         {internalTasks.map(renderCard)}
                    </div>
                </div>
            )}
        </div>
    );
};

