                                            </div>
                                        </div>
                                    </div>
                                </>
                            )}

                            {/* QUANTITY SECTION */}
                            <div>
                                <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('quantity')}</label>
                                <div className="flex flex-col sm:flex-row gap-3">
