                                                      <span className="text-xl font-mono font-bold text-yellow-400">{Math.ceil(reqQty)}</span>
                                                  </div>
                                                  <button 
                                                      onClick={() => handleCreateTaskFromBOM(item.childPart, reqQty, item.id)}
