          {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
            <SettingsTab 
                currentUserRole={currentUserRole}
                users={users}
                onAddUser={onAddUser}
                onUpdatePassword={onUpdatePassword}
                onUpdateUserRole={onUpdateUserRole}
